function solve(nums) {
    let maxSum = 0;
    const n = nums.length;

    // Iterate all possible masks for A and B (each bit represents if the element is in A or B)
    // Since each element can be in A, B, or C, we need 2 bits per element
    // But with n up to 19, 2^19 is manageable (524288 masks)
    const totalMasks = 1 << n;

    for (let maskA = 0; maskA < totalMasks; maskA++) {
        for (let maskB = 0; maskB < totalMasks; maskB++) {
            // Ensure A and B are disjoint
            if ((maskA & maskB) !== 0) continue;

            let xorA = 0;
            let andB = ~0; // Initialize to all 1s for AND
            let xorC = 0;
            let hasB = false;

            for (let i = 0; i < n; i++) {
                const inA = (maskA & (1 << i)) !== 0;
                const inB = (maskB & (1 << i)) !== 0;

                if (inA) {
                    xorA ^= nums[i];
                } else if (inB) {
                    andB &= nums[i];
                    hasB = true;
                } else {
                    xorC ^= nums[i];
                }
            }

            // If B is empty, AND is 0
            const currentAndB = hasB ? andB : 0;
            const currentSum = xorA + currentAndB + xorC;

            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}

